var e=JSON.parse(`[{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"만나고 싶은 사람이 있었다.","JPN":"私には会いたい人がいた。","ENG":"There was someone that I wanted to meet.","TWN":"我有個想見的人。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"어떤 갈등이 벌어지던 클라이맥스에 이르러 빛과 함께 나타나 모든 갈등을 해결하는 사람.","JPN":"どんな争いが起こってもクライマックスには光とともに現れ、すべてを解決してくれる人。","ENG":"He would appear with light during the climax of any conflict and resolve it.","TWN":"不管發生怎樣的危險，都會在危機關頭如超人一般登場，解決一切麻煩之人。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"그 자체만으로도 너무나 눈부셔서 마치 백조와 같았던 사람.","JPN":"存在自体があまりにも眩しくて、まるで白鳥のような人だった。","ENG":"A person who was so radiant and graceful like a swan.","TWN":"他本身就如此耀眼，宛如一隻白天鵝。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 누구에게도 진정으로 이해 받지 못했던 날 인정해 주었던 유일한 사람.","JPN":"そして誰からも理解してもらえなかった私を認めてくれた、唯一の人。","ENG":"The only person who acknowledged me when I was misunderstood by everyone.","TWN":"他是唯一一個真正理解並認可我的人。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그 남자</color>…….","JPN":"<color=#ffd34c>あの男</color>……","ENG":"<color=#ffd34c>The man</color>...","TWN":"<color=#ffd34c>那個男人</color>……"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"나의 세계는 이미 내일을 빼앗겨 버렸고, 그 남자 역시 더는 존재하지 않지만.","JPN":"私の世界はすでに明日を奪われてしまった。あの男もまた存在しない。","ENG":"The future of my world has already been robbed, and he no longer exists.","TWN":"我的世界已經失去了明天，那個人也不再存在了。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"그럼에도 나는 여전히 그 남자와 함께 했던 사건을 떠올리곤 한다.","JPN":"それでも私は、今でもあの男との事件を思い出す。","ENG":"Yet, I still reminisce about the incident I had with the man.","TWN":"儘管如此，我仍會時常回想起和那個男人一起經歷的一切。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그건 무척이나, 오래된 다짐.","JPN":"それはとても古い誓い。","ENG":"That is my old determination.","TWN":"那是非常久遠的誓言。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"그 각본의 끝에 어떤 결말이 기다리고 있다 하더라도.","JPN":"その脚本の終わりにどんな結末が待っていようと……","ENG":"No matter what ending awaits me at the end of it.","TWN":"即使在那個劇本的結尾，等待我的是某種結局。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것을 처음으로 되돌리기 위해서라면, 어떤 배역이라도 받아들이겠다는 선택.","JPN":"すべてを振り出しに戻すためなら、どんな配役でも受け入れる。","ENG":"A choice I made to accept any role if it meant reverting everything to the beginning,","TWN":"為了將一切恢復原狀，我願意接受任何角色。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"그래, 이 회상록은 아마도 여기부터 시작하는 편이 좋겠지.","JPN":"そう、この回想録の導入はここから始めたほうがいいだろう。","ENG":"Yes. I believe starting from here would be appropriate.","TWN":"是的，這段回憶錄或許從這裡開始比較好。"},"stage":{"bg":"GRONIA_HALL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 8일 런던 \\n<color=#ffd34c>심야</color>","JPN":"1888年9月8日　ロンドン\\n<color=#ffd34c>深夜</color>","ENG":"[[","TWN":"1888年9月8日 倫敦\\n<color=#ffd34c>深夜</color>","SCN":"1888年9月8日 伦敦\\n<color=#ffd34c>深夜</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"헉, 허억……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"咳，咳咳……！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"사, 사람……! 사람 살……!","JPN":"た、たす……助けて……！","ENG":"S-somebody...! Please, help m–!","TWN":"救，救……！救命……！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"……커헉!","JPN":"……カハッ！","ENG":"...Gah!","TWN":"……咳嚇！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"……가엾군.","JPN":"……気の毒に。","ENG":"...Pitiful.","TWN":"……可憐。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"그 불쌍한 아이도 그만큼 아팠겠지.","JPN":"あの可哀想な子も、同じぐらい痛かったんだろう。","ENG":"That poor child must have felt as much pain.","TWN":"那個可憐的孩子一定也是這麼痛苦吧。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊，哈啊……！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"어째서…… 어째서 이런 짓을……!","JPN":"どうして、どうしてこんなことを……！","ENG":"Why... Why are you doing this to me...?!","TWN":"為什麼……為什麼要做這種事……！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"어째서냐고?","JPN":"どうして？","ENG":"Why, you ask?","TWN":"為什麼嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RIPPER_SWANSONG_NPC_QM","text":{"KOREA":"그건 이 세계가 너무나 타락했기 때문이야. 그래서 제물이 필요한 거지.","JPN":"それはこの世界があまりにも堕落しすぎたからだよ。だから生贄が必要なんだ。","ENG":"That's because the world has lost its grace. And we need to offer a sacrifice.","TWN":"那是因為這個世界已經墮落得太深了，所以才需要祭品。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"RIPPER_SWANSONG_NPC_QM","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};